struct StackNode {
    int data;
    struct StackNode *next;
};

// Push operation - insert at beginning
void push(struct StackNode **top, int value) {
    struct StackNode *newNode = (struct StackNode*)malloc(sizeof(struct StackNode));
    newNode->data = value;
    newNode->next = *top;
    *top = newNode;
}

// Pop operation - delete from beginning
int pop(struct StackNode **top) {
    if (*top == NULL) return -1;
    struct StackNode *temp = *top;
    int value = temp->data;
    *top = (*top)->next;
    free(temp);
    return value;
}

// Check if stack is empty
int isEmpty(struct StackNode *top) {
    return top == NULL;
}

struct QueueNode {
    int data;
    struct QueueNode *next;
};

struct Queue {
    struct QueueNode *front;
    struct QueueNode *rear;
};

// Enqueue - insert at rear
void enqueue(struct Queue *q, int value) {
    struct QueueNode *newNode = (struct QueueNode*)malloc(sizeof(struct QueueNode));
    newNode->data = value;
    newNode->next = NULL;

    if (q->rear == NULL) {
        q->front = q->rear = newNode;
    } else {
        q->rear->next = newNode;
        q->rear = newNode;
    }
}

// Dequeue - delete from front
int dequeue(struct Queue *q) {
    if (q->front == NULL) return -1;
    struct QueueNode *temp = q->front;
    int value = temp->data;
    q->front = q->front->next;

    if (q->front == NULL) q->rear = NULL;
    free(temp);
    return value;
}

struct PolynomialNode {
    int coefficient;
    int exponent;
    struct PolynomialNode *next;
};

// Add two polynomials
struct PolynomialNode* addPolynomials(struct PolynomialNode *poly1, struct PolynomialNode *poly2) {
    struct PolynomialNode *result = NULL;
    struct PolynomialNode **tail = &result;

    while (poly1 && poly2) {
        struct PolynomialNode *newNode = (struct PolynomialNode*)malloc(sizeof(struct PolynomialNode));

        if (poly1->exponent > poly2->exponent) {
            newNode->coefficient = poly1->coefficient;
            newNode->exponent = poly1->exponent;
            poly1 = poly1->next;
        } else if (poly2->exponent > poly1->exponent) {
            newNode->coefficient = poly2->coefficient;
            newNode->exponent = poly2->exponent;
            poly2 = poly2->next;
        } else {
            newNode->coefficient = poly1->coefficient + poly2->coefficient;
            newNode->exponent = poly1->exponent;
            poly1 = poly1->next;
            poly2 = poly2->next;
        }
        newNode->next = NULL;
        *tail = newNode;
        tail = &newNode->next;
    }
    return result;
}
